do $$
declare
  child_count int;
  parent_count int;
  set_count int;
  unsupported_finish_count int;
  existing_child_count int;
  id_collision_count int;
begin
  select count(*) into child_count from pkg06d_active_child_printings;
  select count(distinct card_print_id) into parent_count from pkg06d_active_child_printings;
  select count(distinct set_key) into set_count from pkg06d_active_child_printings;
  select count(*) into unsupported_finish_count
  from pkg06d_active_child_printings target
  left join public.finish_keys fk
    on fk.key = target.finish_key
   and fk.is_active = true
  where fk.key is null;
  select count(*) into existing_child_count
  from pkg06d_active_child_printings target
  join public.card_printings cpr
    on cpr.card_print_id = target.card_print_id
   and cpr.finish_key = target.finish_key;
  select count(*) into id_collision_count
  from pkg06d_active_child_printings target
  join public.card_printings cpr on cpr.id = target.card_printing_id;

  if child_count <> 319 then raise exception 'PKG-06D child count drift: %', child_count; end if;
  if parent_count <> 318 then raise exception 'PKG-06D parent count drift: %', parent_count; end if;
  if set_count <> 3 then raise exception 'PKG-06D set count drift: %', set_count; end if;
  if unsupported_finish_count <> 0 then raise exception 'PKG-06D unsupported finish count: %', unsupported_finish_count; end if;
  if existing_child_count <> 0 then raise exception 'PKG-06D existing child count: %', existing_child_count; end if;
  if id_collision_count <> 0 then raise exception 'PKG-06D id collision count: %', id_collision_count; end if;
end $$;

