  id,
  card_print_id,
  finish_key,
  is_provisional,
  provenance_source,
  provenance_ref,
  created_by
)
select
  card_printing_id,
  card_print_id,
  finish_key,
  false,
  provenance_source,
  provenance_ref,
  created_by
from pkg06d_active_child_printings;

select
  'PKG-06D-ACTIVE-FINISH-CHILD-PRINTING-INSERTS'::text as package_id,
  '1b96ceb09853c30e4f73a8a135a5d6c9f8632d8fef9cc6c3457496e9d1589bcd'::text as source_readiness_fingerprint,
  'c67558f261d8d70faf6beac7f63faafa5b627cf0cf7dfeb09989da5e617055b1'::text as package_fingerprint,
